#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10,INF=1e9;

struct Node{
    int sum,mx,mxs,mxc,mn,mns,mnc,ts,tmx,tmn;
    Node operator+(Node x)const{
        Node res;
        res.sum=sum+x.sum;
        res.mx=max(mx,x.mx);
        if(mx==x.mx){
            res.mxs=max(mxs,x.mxs);
            res.mxc=mxc+x.mxc;
        }else if(mx<x.mx){
            res.mxs=max(mx,x.mxs);
            res.mxc=x.mxc;
        }else{
            res.mxs=max(x.mx,mxs);
            res.mxc=mxc;
        }
        res.mn=min(mn,x.mn);
        if(mn==x.mn){
            res.mns=min(mns,x.mns);
            res.mnc=mnc+x.mnc;
        }else if(mn>x.mn){
            res.mns=min(mn,x.mns);
            res.mnc=x.mnc;
        }else{
            res.mns=min(mns,x.mn);
            res.mnc=mnc;
        }
        res.tmx=-INF,res.tmn=INF;
        res.ts=0;
        return res;
    }
}t[N<<2];

int n,m,a[N];

void build(int cur,int l,int r){
    t[cur].tmx=-INF,t[cur].tmn=INF;
    t[cur].ts=0;
    if(l==r){
        t[cur].sum=t[cur].mx=t[cur].mn=a[l];
        t[cur].mxc=t[cur].mnc=1;
        t[cur].mxs=-INF,t[cur].mns=INF;
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=t[cur*2]+t[cur*2+1];
}

void push_down(int,int,int);

void chg(int cur,int l,int r,int x,int tp){
    if(tp==1){
        t[cur].ts+=x;
        if(t[cur].tmx>-INF) t[cur].tmx+=x;
        if(t[cur].tmn<INF) t[cur].tmn+=x;
        t[cur].mx+=x,t[cur].mn+=x;
		if(t[cur].mns!=INF) t[cur].mns+=x;
		if(t[cur].mxs!=-INF) t[cur].mxs+=x;
        t[cur].sum+=(r-l+1)*x;
    }else if(tp==2){
        t[cur].tmx=max(t[cur].tmx,x);
        t[cur].tmn=max(t[cur].tmn,x); 
        if(t[cur].mn>=x)
            return;
        if(x<t[cur].mns){
        	if(t[cur].mxs==t[cur].mn) t[cur].mxs=x;
        	if(t[cur].mx==t[cur].mn) t[cur].mx=x;
            t[cur].sum+=(x-t[cur].mn)*t[cur].mnc;
            t[cur].mn=x;
        }else{
            push_down(cur,l,r);
            t[cur]=t[cur*2]+t[cur*2+1];
        }
    }else{
        t[cur].tmn=min(t[cur].tmn,x);
        t[cur].tmx=min(t[cur].tmx,x);
        if(t[cur].mx<=x)
            return;
        if(x>t[cur].mxs){
        	if(t[cur].mns==t[cur].mx) t[cur].mns=x;
        	if(t[cur].mn==t[cur].mx) t[cur].mn=x;
            t[cur].sum+=(x-t[cur].mx)*t[cur].mxc;
            t[cur].mx=x;
        }else{
            push_down(cur,l,r);
            t[cur]=t[cur*2]+t[cur*2+1];
        }
    }
}

void push_down(int cur,int l,int r){
	//if(l==r)
	//	return;
    int mid=l+r>>1;
    if(t[cur].ts){
        chg(cur*2,l,mid,t[cur].ts,1);
        chg(cur*2+1,mid+1,r,t[cur].ts,1);
        t[cur].ts=0;
    }
    if(t[cur].tmx>-INF){
        chg(cur*2,l,mid,t[cur].tmx,2);
        chg(cur*2+1,mid+1,r,t[cur].tmx,2);
        t[cur].tmx=-INF;
    }
    if(t[cur].tmn<INF){
        chg(cur*2,l,mid,t[cur].tmn,3);
        chg(cur*2+1,mid+1,r,t[cur].tmn,3);
        t[cur].tmn=INF;
    }
}

Node query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(y<=mid)
        return query(cur*2,l,mid,x,y);
    if(x>mid)
        return query(cur*2+1,mid+1,r,x,y);
    return query(cur*2,l,mid,x,y)+query(cur*2+1,mid+1,r,x,y);
}

void modify(int cur,int l,int r,int x,int y,int k,int tp){
//	printf("%d %d\n",l,r);
    if(x<=l && r<=y){
        chg(cur,l,r,k,tp);
        return;
    }
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k,tp);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k,tp);
    t[cur]=t[cur*2]+t[cur*2+1];
}

int main(){
//	freopen("input.in","r",stdin);
//	freopen("output.out","w",stdout);
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    build(1,1,n);
    scanf("%d",&m);
    while(m--){
        int op,l,r,x;
        scanf("%d%d%d",&op,&l,&r);
        if(op<=3){
            scanf("%d",&x);
            modify(1,1,n,l,r,x,op);
        }else{
            Node res=query(1,1,n,l,r);
            if(op==4)
                printf("%d\n",res.sum);
            if(op==5)
                printf("%d\n",res.mx);
            if(op==6)
                printf("%d\n",res.mn);
        }
//        printf("sum: %d\n",t[1].sum);
    }
    return 0;
}
